class Solution:
    def countGoodIntegers(self, n: int, k: int) -> int:
        def dfs(n, k, prefix, count):
            if n == 0:
                return count
            if len(prefix) >= k and prefix == prefix[::-1]:
                return dfs(n-1, k, '', 0)
            count += n
            for i in range(1, 10):
                dfs(n-1, k, prefix + str(i), count)
            return count

        return dfs(n, k, '', 0)
